function parsePackageLabelGallonsEstimate(packageLabel) {
  const match = String(packageLabel || "").match(
    /(\d+(?:\.\d+)?)\s*(?:gal|gallon)/i
  );
  if (!match) return null;
  const n = Number(match[1]);
  return Number.isFinite(n) ? n : null;
}

function filterInventoryEligibleResponses(
  raw,
  activeMembership,
  isManager,
  teamAssignments,
  repProfiles,
  sessionUserId
) {
  if (!activeMembership?.organization_id) return [];
  const orgId = activeMembership.organization_id;
  return (raw || []).filter((res) => {
    const q = res.quote;
    if (!q || q.organization_id !== orgId) return false;
    if (!isManager) return true;

    const assignedRepProfileIds = (teamAssignments || [])
      .filter(
        (assignment) =>
          assignment.manager_profile_id === sessionUserId ||
          assignment.manager_user_id === sessionUserId
      )
      .map((assignment) => assignment.rep_profile_id)
      .filter(Boolean);

    const assignedRepEmails = (repProfiles || [])
      .filter(
        (rep) =>
          assignedRepProfileIds.includes(rep.id) ||
          assignedRepProfileIds.includes(rep.user_id)
      )
      .map((rep) => String(rep.email || "").toLowerCase())
      .filter(Boolean);

    const quoteRepEmail = String(q.rep_email || "").toLowerCase();

    return (
      assignedRepProfileIds.includes(q.user_id) ||
      assignedRepEmails.includes(quoteRepEmail)
    );
  });
}

function collectApprovedProductLines(eligibleResponses) {
  const lines = [];
  (eligibleResponses || []).forEach((res) => {
    const customerName =
      res.decision_data?.customer_name || res.quote?.customer_name || "";
    const customerEmail =
      res.decision_data?.customer_email || res.quote?.customer_email || "";
    const rows = res.decision_data?.responses || [];
    rows.forEach((row) => {
      if (row.decision !== "approved") return;
      if (row.type === "equipment") return;
      if (String(row.package || "").toLowerCase() === "equipment") return;
      lines.push({
        responseId: res.id,
        quoteId: res.quote_id,
        createdAt: res.created_at,
        customerName,
        customerEmail,
        product: row.product || "—",
        package: row.package || "",
        price: Number(row.price || 0),
        quoteItemId: row.quote_item_id,
      });
    });
  });
  return lines;
}

function normalizeDashboardName(str) {
  return String(str || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function getProposalProductResponseArray(row) {
  const dd = row.decision_data || {};
  return Array.isArray(dd.responses)
    ? dd.responses
    : Array.isArray(row.responses)
    ? row.responses
    : [];
}

function collectProposalDecisionLines(row) {
  const products = getProposalProductResponseArray(row);
  const dd = row.decision_data || {};
  const equipment = Array.isArray(dd.equipment)
    ? dd.equipment
    : Array.isArray(row.equipment)
    ? row.equipment
    : [];
  return [...products, ...equipment];
}

function parseTimelineMs(value) {
  if (!value) return null;
  const ms = Date.parse(String(value));
  return Number.isFinite(ms) ? ms : null;
}

function formatTimelineDateLabel(iso) {
  const ms = parseTimelineMs(iso);
  if (ms == null) return null;
  try {
    return new Date(ms).toLocaleString(undefined, {
      month: "short",
      day: "numeric",
      year: "numeric",
      hour: "numeric",
      minute: "2-digit",
    });
  } catch {
    return null;
  }
}

/** Library row badge — deterministic labels from quote fields only. */
function quoteLibraryStatusMeta(quote) {
  const status = String(quote?.status || "").trim().toLowerCase();
  const review = String(quote?.review_status || "").trim().toLowerCase();
  if (status === "sent") {
    if (review === "submitted") {
      return {
        label: "Responded",
        hint: "Customer submitted decisions",
        pillBg: "#dbeafe",
        pillFg: "#1e40af",
        pillBorder: "#93c5fd",
      };
    }
    return {
      label: "Awaiting customer",
      hint: "Proposal sent",
      pillBg: "#fff7ed",
      pillFg: "#c2410c",
      pillBorder: "#fdba74",
    };
  }
  if (status === "draft" || status === "") {
    return {
      label: "Draft",
      hint: "Not sent yet",
      pillBg: "#f1f5f9",
      pillFg: "#475569",
      pillBorder: "#cbd5e1",
    };
  }
  return {
    label: String(quote?.status || "Saved").trim() || "Saved",
    hint: review || "",
    pillBg: "#f8fafc",
    pillFg: "#0f172a",
    pillBorder: "#e2e8f0",
  };
}

