/** Lightweight insights from tracked proposal views + responses only (no fabricated metrics). */
function buildProposalEngagementInsights(quotes, proposalResponses, viewEvents) {
  const insights = [];
  const now = Date.now();
  const weekMs = 7 * 24 * 60 * 60 * 1000;

  const viewsLast7 = (viewEvents || []).filter((ev) => {
    const ms = parseTimelineMs(ev.viewed_at);
    return ms != null && ms >= now - weekMs;
  }).length;

  const viewsPrev7 = (viewEvents || []).filter((ev) => {
    const ms = parseTimelineMs(ev.viewed_at);
    return ms != null && ms >= now - 2 * weekMs && ms < now - weekMs;
  }).length;

  if (viewsLast7 >= 2 && viewsLast7 > viewsPrev7) {
    insights.push("Proposal engagement activity increased this week.");
  }

  const viewedQuoteIds = new Set(
    (viewEvents || []).map((ev) => ev.quote_id).filter(Boolean)
  );
  let viewedWithApprovedDemand = 0;
  (proposalResponses || []).forEach((res) => {
    if (!res.quote_id || !viewedQuoteIds.has(res.quote_id)) return;
    const hasApproved = collectProposalDecisionLines(res).some(
      (ln) => ln.decision === "approved"
    );
    if (hasApproved) viewedWithApprovedDemand += 1;
  });
  if (viewedWithApprovedDemand >= 2) {
    insights.push("Viewed proposals are converting into approved demand.");
  }

  const firstViewByQuote = {};
  (viewEvents || []).forEach((ev) => {
    const qid = ev.quote_id;
    if (!qid || !ev.viewed_at) return;
    const ms = parseTimelineMs(ev.viewed_at);
    if (ms == null) return;
    const cur = firstViewByQuote[qid];
    if (!cur || ms < cur.ms) firstViewByQuote[qid] = { ms, at: ev.viewed_at };
  });

  const deltasRecent = [];
  const deltasPrior = [];
  (quotes || []).forEach((q) => {
    const sentMs =
      parseTimelineMs(q.updated_at) ?? parseTimelineMs(q.created_at);
    const fv = firstViewByQuote[q.id];
    if (!sentMs || !fv) return;
    const hours = (fv.ms - sentMs) / 3600000;
    if (!Number.isFinite(hours) || hours < 0 || hours > 720) return;
    if (fv.ms >= now - weekMs) deltasRecent.push(hours);
    else if (fv.ms >= now - 2 * weekMs && fv.ms < now - weekMs)
      deltasPrior.push(hours);
  });

  const avg = (arr) =>
    arr.length ? arr.reduce((s, x) => s + x, 0) / arr.length : null;
  const avgRecent = avg(deltasRecent);
  const avgOlder = avg(deltasPrior);
  if (
    avgRecent != null &&
    avgOlder != null &&
    deltasRecent.length >= 2 &&
    deltasPrior.length >= 2 &&
    avgRecent < avgOlder * 0.85
  ) {
    insights.push("Customers are reviewing proposals more quickly.");
  }

  return insights.slice(0, 4);
}

function buildCrmTimelineEntries({
  quotes,
  proposalResponses,
  ocrEvents,
  viewEvents = [],
  limit = 10,
}) {
  const quoteMap = {};
  (quotes || []).forEach((q) => {
    if (q?.id) quoteMap[q.id] = q;
  });

  const respondedQuoteIds = new Set(
    (proposalResponses || []).map((r) => r.quote_id).filter(Boolean)
  );

  const firstViewByQuote = {};
  (viewEvents || []).forEach((ev) => {
    const qid = ev.quote_id;
    if (!qid || !ev.viewed_at) return;
    const ms = parseTimelineMs(ev.viewed_at);
    if (ms == null) return;
    const cur = firstViewByQuote[qid];
    if (!cur || ms < cur.ms) firstViewByQuote[qid] = { ms, at: ev.viewed_at };
  });

  const rows = [];

  (quotes || []).forEach((q) => {
    const cust = String(q.customer_name || "").trim() || "Customer";
    const ref =
      q.id != null
        ? String(q.id).replace(/-/g, "").slice(0, 8).toUpperCase()
        : "";
    const refSuffix = ref ? ` · ${ref}` : "";
    const cms = parseTimelineMs(q.created_at);
    rows.push({
      id: `qc-${q.id}`,
      kind: "quote_created",
      sortMs: cms ?? 0,
      dateLabel: formatTimelineDateLabel(q.created_at),
      badge: "Created",
      accent: "blue",
      title: "Proposal created",
      detail: `${cust}${refSuffix}`,
    });

    const sentLike =
      String(q.status || "").toLowerCase() === "sent" ||
      Boolean(q.rep_signature);
    if (sentLike) {
      const sms =
        parseTimelineMs(q.updated_at) ??
        parseTimelineMs(q.created_at) ??
        0;
      rows.push({
        id: `ps-${q.id}`,
        kind: "proposal_sent",
        sortMs: sms,
        dateLabel:
          formatTimelineDateLabel(q.updated_at) ||
          formatTimelineDateLabel(q.created_at),
        badge: "Sent",
        accent: "orange",
        title: "Proposal sent",
        detail: `${cust}${refSuffix}`,
      });

      const fv = firstViewByQuote[q.id];
      if (fv) {
        rows.push({
          id: `pv-${q.id}`,
          kind: "proposal_viewed",
          sortMs: fv.ms,
          dateLabel: formatTimelineDateLabel(fv.at),
          badge: "Viewed",
          accent: "green",
          title: "Proposal viewed",
          detail: `${cust}${refSuffix}`,
        });
      }

      if (!respondedQuoteIds.has(q.id)) {
        const arMs =
          parseTimelineMs(q.updated_at) ??
          parseTimelineMs(q.created_at) ??
          0;
        rows.push({
          id: `ar-${q.id}`,
          kind: "awaiting_response",
          sortMs: arMs,
          dateLabel:
            formatTimelineDateLabel(q.updated_at) ||
            formatTimelineDateLabel(q.created_at),
          badge: "Waiting",
          accent: "orange",
          title: "Awaiting response",
          detail: `No customer submission yet · ${cust}${refSuffix}`,
        });
      }
    }
  });

  (proposalResponses || []).forEach((res) => {
    const quote = quoteMap[res.quote_id];
    const cust = String(quote?.customer_name || "").trim() || "Customer";
    const lines = collectProposalDecisionLines(res);
    let approved = 0;
    let declined = 0;
    lines.forEach((ln) => {
      if (ln.decision === "approved") approved += 1;
      else if (ln.decision === "declined") declined += 1;
    });
    const rms = parseTimelineMs(res.created_at) ?? 0;
    const ref =
      res.quote_id != null
        ? String(res.quote_id).replace(/-/g, "").slice(0, 8).toUpperCase()
        : "";
    const refSuffix = ref ? ` · ${ref}` : "";

    rows.push({
      id: `cr-${res.id}`,
      kind: "customer_response",
      sortMs: rms,
      dateLabel: formatTimelineDateLabel(res.created_at),
      badge: "Responded",
      accent: "blue",
      title: "Customer responded",
      detail: `${cust}${refSuffix} · Approved ${approved} · Declined ${declined}`,
    });

    if (approved > 0) {
      rows.push({
        id: `ad-${res.id}`,
        kind: "approved_demand",
        sortMs: rms,
        dateLabel: formatTimelineDateLabel(res.created_at),
        badge: "Demand",
        accent: "green",
        title: "Approved demand generated",
        detail: `${approved} approved line(s) · ${cust}${refSuffix}`,
      });
    }

    if (declined > 0) {
      rows.push({
        id: `df-${res.id}`,
        kind: "declined_followup",
        sortMs: rms,
        dateLabel: formatTimelineDateLabel(res.created_at),
        badge: "Follow-up",
        accent: "orange",
        title: "Declined lines requiring follow-up",
        detail: `${declined} declined line(s) · ${cust}${refSuffix}`,
      });
    }
  });

  (ocrEvents || []).forEach((ev) => {
    const ms = parseTimelineMs(ev.created_at) ?? 0;
    const brand = String(ev.detected_brand || "").trim();
    const visc = String(ev.detected_viscosity || "").trim();
    const matchOk = ev.match_success === true;
    const src = String(ev.image_source_type || "").replace(/_/g, " ") || "scan";
    const bits = [
      brand ? brand : null,
      visc ? visc : null,
      matchOk ? "Klondike match" : "No confident match",
      src,
    ].filter(Boolean);
    rows.push({
      id: `ocr-${ev.id}`,
      kind: "ocr",
      sortMs: ms,
      dateLabel: formatTimelineDateLabel(ev.created_at),
      badge: "OCR",
      accent: "blue",
      title: "Label scan activity",
      detail: bits.join(" · "),
    });
  });

  rows.sort((a, b) => {
    if (b.sortMs !== a.sortMs) return b.sortMs - a.sortMs;
    return (
      (CRM_TIMELINE_KIND_ORDER[a.kind] ?? 99) -
      (CRM_TIMELINE_KIND_ORDER[b.kind] ?? 99)
    );
  });

  return rows.slice(0, limit);
}

function buildQuoteItemLookupById(itemRows) {
  const map = {};
  (itemRows || []).forEach((r) => {
    if (r?.id != null) map[r.id] = r;
  });
  return map;
}

function getDashboardDemandCategoryFromProductName(productName) {
  const n = String(productName || "").toLowerCase();
  if (n.includes("grease")) return "Grease";
  if (n.includes("hydraulic")) return "Hydraulic Fluids";
  if (n.includes("transmission") || /\batf\b/i.test(n)) return "Transmission Fluids";
  if (n.includes("coolant")) return "Coolants / Chemicals";
  if (/\bgear\b/i.test(n) && (n.includes("lubricant") || n.includes("oil")))
    return "Gear Oils";
  if (
    n.includes("engine") ||
    n.includes("diesel") ||
    n.includes("motor oil") ||
    /\d+w-\d+/i.test(n)
  )
    return "HD Engine Oils";
  return "Other";
}

/** Aligns outbound proposal counts with existing dashboard semantics (portal vs dealer admin). */
function countOutboundProposalQuotes(quotes, mode) {
  const qs = quotes || [];
  if (mode === "dealer") {
    return qs.filter((q) => String(q?.status || "").toLowerCase() === "sent")
      .length;
  }
  return qs.filter(
    (q) => Boolean(q?.rep_signature) || Boolean(String(q?.rep_email || "").trim())
  ).length;
}

function incrementCount(map, rawKey, labelFallback) {
  const keyRaw = String(rawKey || "").trim();
  const key = keyRaw || labelFallback;
  if (!map[key]) map[key] = 0;
  map[key] += 1;
  return map;
}

function pickTopDemandLabel(counts, minCount = 1) {
  const entries = Object.entries(counts || {}).filter(
    ([, n]) => n >= minCount
  );
  if (!entries.length) return null;
  entries.sort(
    (a, b) => b[1] - a[1] || String(a[0]).localeCompare(String(b[0]))
  );
  return { label: entries[0][0], count: entries[0][1] };
}

function buildProposalConversionIntelligence(quotes, proposalResponses, mode) {
  const proposalsSent = countOutboundProposalQuotes(quotes, mode);
  const responses = proposalResponses || [];
  const responsesReceived = responses.length;

  let approvedLines = 0;
  let declinedLines = 0;
  const approvedProductCounts = {};
  const declinedProductCounts = {};
  const approvedCategoryCounts = {};
  const declinedCategoryCounts = {};

  responses.forEach((res) => {
    collectProposalDecisionLines(res).forEach((ln) => {
      const productLabel = String(ln.product || "").trim() || "—";
      if (ln.decision === "approved") {
        approvedLines += 1;
        incrementCount(approvedProductCounts, ln.product, "—");
        const cat = getDashboardDemandCategoryFromProductName(productLabel);
        incrementCount(approvedCategoryCounts, cat, "Other");
      } else if (ln.decision === "declined") {
        declinedLines += 1;
        incrementCount(declinedProductCounts, ln.product, "—");
        const cat = getDashboardDemandCategoryFromProductName(productLabel);
        incrementCount(declinedCategoryCounts, cat, "Other");
      }
    });
  });

  const decisionsTotal = approvedLines + declinedLines;
  const approvalRatioPercent =
    decisionsTotal > 0
      ? Math.round((approvedLines / decisionsTotal) * 100)
      : null;

  const topApprovedProductRow = pickTopDemandLabel(approvedProductCounts);
  const topDeclinedProductRow = pickTopDemandLabel(declinedProductCounts);
  const topApprovedCategoryRow = pickTopDemandLabel(approvedCategoryCounts);
  const topDeclinedCategoryRow = pickTopDemandLabel(declinedCategoryCounts);

  const topApprovedProductLabel =
    topApprovedProductRow && topApprovedProductRow.label !== "—"
      ? topApprovedProductRow.label
      : null;
  const topDeclinedProductLabel =
    topDeclinedProductRow && topDeclinedProductRow.label !== "—"
      ? topDeclinedProductRow.label
      : null;
  const topApprovedCategoryLabel = topApprovedCategoryRow?.label || null;
  const topDeclinedCategoryLabel = topDeclinedCategoryRow?.label || null;

  const insights = [];
  if (approvedLines > 0 && responsesReceived > 0) {
    insights.push(
      "Customer responses are beginning to convert into approved demand."
    );
  }
  if (declinedLines > 0) {
    insights.push(
      "Declined lines may need follow-up before the next proposal revision."
    );
  }
  if (
    topApprovedCategoryLabel &&
    approvedLines >= 2 &&
    topApprovedCategoryRow
  ) {
    const catShareApproved =
      approvedLines > 0
        ? topApprovedCategoryRow.count / approvedLines
        : 0;
    if (
      catShareApproved >= 0.45 &&
      topApprovedCategoryLabel !== "Other"
    ) {
      insights.push(
        `Approved demand is concentrated in ${topApprovedCategoryLabel}.`
      );
    }
  }
  if (
    topDeclinedCategoryLabel &&
    declinedLines >= 2 &&
    topDeclinedCategoryRow
  ) {
    const catShareDeclined =
      declinedLines > 0
        ? topDeclinedCategoryRow.count / declinedLines
        : 0;
    if (catShareDeclined >= 0.45 && topDeclinedCategoryLabel !== "Other") {
      insights.push(
        `Most declined rows group under ${topDeclinedCategoryLabel}—review competitiveness on the next recommendation pass.`
      );
    }
  }
  if (proposalsSent > 0 && responsesReceived === 0) {
    insights.push(
      "Outbound proposals recorded—customer decision submissions will appear once responses arrive."
    );
  }

  const hasProposalMotion = proposalsSent > 0 || responsesReceived > 0;

  return {
    proposalsSent,
    responsesReceived,
    approvedLines,
    declinedLines,
    decisionsTotal,
    approvalRatioPercent,
    topApprovedProductLabel,
    topDeclinedProductLabel,
    topApprovedCategoryLabel,
    topDeclinedCategoryLabel,
    insights,
    hasProposalMotion,
  };
}

