function summarizeApprovedDemandFromProposalRows(responseRows, quoteItemByIdMap) {
  const lines = [];
  (responseRows || []).forEach((row) => {
    getProposalProductResponseArray(row).forEach((item) => {
      if (item.decision !== "approved") return;
      if (item.type === "equipment") return;
      if (String(item.package || "").toLowerCase() === "equipment") return;
      lines.push(item);
    });
  });

  const groups = {};
  const categoryUnitTotals = {};

  lines.forEach((item) => {
    const pk = `${String(item.product || "")
      .trim()
      .toLowerCase()}__${String(item.package || "").trim().toLowerCase()}`;
    if (!groups[pk]) groups[pk] = { qty: 0 };

    let qty = 1;
    const qid = item.quote_item_id;
    if (qid && quoteItemByIdMap && quoteItemByIdMap[qid]) {
      const qi = quoteItemByIdMap[qid];
      qty =
        qi.quantity != null && Number.isFinite(Number(qi.quantity))
          ? Number(qi.quantity)
          : 1;
    }

    groups[pk].qty += qty;
    const cat = getDashboardDemandCategoryFromProductName(item.product);
    categoryUnitTotals[cat] = (categoryUnitTotals[cat] || 0) + qty;
  });

  const distinctSkus = Object.keys(groups).length;
  const totalUnits = Object.values(groups).reduce((sum, g) => sum + g.qty, 0);
  let topCategory = null;
  let maxUnits = -1;
  Object.entries(categoryUnitTotals).forEach(([c, u]) => {
    if (u > maxUnits) {
      maxUnits = u;
      topCategory = c;
    }
  });
  const categoryShare =
    totalUnits > 0 && topCategory != null && categoryUnitTotals[topCategory] != null
      ? Math.round((categoryUnitTotals[topCategory] / totalUnits) * 100)
      : 0;

  return {
    distinctSkus,
    totalUnits,
    approvedLineCount: lines.length,
    topCategory,
    categoryShare,
    categoryUnitTotals,
  };
}

/** Package-style rollup from proposal line text only (demand visibility, not ERP). */
function classifyDemandPackageBucket(pkgRaw, productRaw) {
  const p = `${String(pkgRaw || "").trim()} ${String(productRaw || "").trim()}`.toLowerCase();
  if (/\btote\b|ibc|bulk\s*tote/.test(p)) return "Tote / bulk";
  if (/\bdrum\b/.test(p)) return "Drum";
  if (/\bpail\b|\bcube\b/.test(p)) return "Pail / cube";
  if (/\bcase\b|\bbox\b|\bcarton\b/.test(p)) return "Case / carton";
  if (/qt|quart|liter|litre|gallon|\bjug\b/.test(p)) return "Jug / quart / liter";
  return "Other package";
}

function approvedDemandLineQty(item, quoteItemById) {
  let qty = 1;
  const qid = item.quote_item_id;
  if (qid && quoteItemById?.[qid]) {
    const qi = quoteItemById[qid];
    qty =
      qi.quantity != null && Number.isFinite(Number(qi.quantity))
        ? Number(qi.quantity)
        : 1;
  }
  return qty;
}

/**
 * Territory-wide approved-demand rollup for Klondike Admin inventory intelligence.
 * Uses proposal responses + quote_items only—no warehouse or stock data.
 */
function buildKlondikeTerritoryInventoryModel({
  responseRows,
  quoteItems,
  quotes,
  dealerOrgs,
}) {
  const quoteItemById = buildQuoteItemLookupById(quoteItems);
  const quoteById = {};
  (quotes || []).forEach((q) => {
    if (q?.id) quoteById[q.id] = q;
  });
  const orgNameById = {};
  (dealerOrgs || []).forEach((o) => {
    if (o?.id) orgNameById[o.id] = o.name || "Dealer";
  });

  const approvedLines = [];
  (responseRows || []).forEach((row) => {
    const ms = parseTimelineMs(row.created_at) ?? 0;
    const quote = quoteById[row.quote_id];
    const orgId = quote?.organization_id || null;
    getProposalProductResponseArray(row).forEach((item) => {
      if (item.decision !== "approved") return;
      if (item.type === "equipment") return;
      if (String(item.package || "").toLowerCase() === "equipment") return;
      approvedLines.push({
        item,
        quote_id: row.quote_id,
        org_id: orgId,
        created_ms: ms,
      });
    });
  });

  const skuMap = {};
  const categoryUnitTotals = {};
  const dealerUnits = {};
  const packageBuckets = {};
  let totalUnits = 0;
  let syntheticUnits = 0;

  const now = Date.now();
  const dayMs = 24 * 60 * 60 * 1000;
  const sevenMs = 7 * dayMs;
  const windowMs = 14 * dayMs;
  const catRecent = {};
  const catPrior = {};
  const skuRecent = {};
  const skuPrior = {};
  const packageBucketsRecent = {};
  const packageBucketsPrior = {};
  let syntheticRecent = 0;
  let syntheticPrior = 0;
  let hydraulicToteRecent = 0;
  let hydraulicTotePrior = 0;
  let unitsLast7d = 0;
  let unitsLast14d = 0;
  let unitsPrior14d = 0;

  approvedLines.forEach(({ item, org_id, created_ms }) => {
    const qty = approvedDemandLineQty(item, quoteItemById);
    const pk = `${String(item.product || "")
      .trim()
      .toLowerCase()}__${String(item.package || "").trim().toLowerCase()}`;
    const cat = getDashboardDemandCategoryFromProductName(item.product);
    const bucket = classifyDemandPackageBucket(item.package, item.product);
    const isSyntheticLine = /synthetic/i.test(String(item.product || ""));

    totalUnits += qty;
    if (isSyntheticLine) {
      syntheticUnits += qty;
    }

    if (!skuMap[pk]) {
      skuMap[pk] = {
        product: String(item.product || "").trim() || "—",
        package: String(item.package || "").trim() || "—",
        totalUnits: 0,
        lineCount: 0,
      };
    }
    skuMap[pk].totalUnits += qty;
    skuMap[pk].lineCount += 1;

    categoryUnitTotals[cat] = (categoryUnitTotals[cat] || 0) + qty;

    if (org_id) {
      dealerUnits[org_id] = (dealerUnits[org_id] || 0) + qty;
    }

    packageBuckets[bucket] = (packageBuckets[bucket] || 0) + qty;

    if (created_ms > 0) {
      if (created_ms >= now - sevenMs) {
        unitsLast7d += qty;
      }
      if (created_ms >= now - windowMs) {
        unitsLast14d += qty;
        catRecent[cat] = (catRecent[cat] || 0) + qty;
        skuRecent[pk] = (skuRecent[pk] || 0) + qty;
        packageBucketsRecent[bucket] = (packageBucketsRecent[bucket] || 0) + qty;
        if (isSyntheticLine) syntheticRecent += qty;
        if (cat === "Hydraulic Fluids" && bucket === "Tote / bulk") {
          hydraulicToteRecent += qty;
        }
      } else if (
        created_ms >= now - 2 * windowMs &&
        created_ms < now - windowMs
      ) {
        unitsPrior14d += qty;
        catPrior[cat] = (catPrior[cat] || 0) + qty;
        skuPrior[pk] = (skuPrior[pk] || 0) + qty;
        packageBucketsPrior[bucket] = (packageBucketsPrior[bucket] || 0) + qty;
        if (isSyntheticLine) syntheticPrior += qty;
        if (cat === "Hydraulic Fluids" && bucket === "Tote / bulk") {
          hydraulicTotePrior += qty;
        }
      }
    }
  });

  const toteRecent = Number(packageBucketsRecent["Tote / bulk"] || 0);
  const totePrior = Number(packageBucketsPrior["Tote / bulk"] || 0);

  const lineCount = approvedLines.length;
  const distinctSkuCount = Object.keys(skuMap).length;

  const topSkus = Object.values(skuMap)
    .slice()
    .sort((a, b) => b.totalUnits - a.totalUnits)
    .slice(0, 15);

  const categoryRows = Object.entries(categoryUnitTotals)
    .map(([name, units]) => ({
      name,
      units,
      sharePct:
        totalUnits > 0 ? Math.round((units / totalUnits) * 1000) / 10 : 0,
    }))
    .sort((a, b) => b.units - a.units);

  const dealerConcentration = Object.entries(dealerUnits)
    .map(([id, units]) => ({
      organization_id: id,
      name: orgNameById[id] || "Dealer",
      units,
      sharePct:
        totalUnits > 0 ? Math.round((units / totalUnits) * 1000) / 10 : 0,
    }))
    .sort((a, b) => b.units - a.units);

  const packageRows = Object.entries(packageBuckets)
    .map(([name, units]) => ({
      name,
      units,
      sharePct:
        totalUnits > 0 ? Math.round((units / totalUnits) * 1000) / 10 : 0,
    }))
    .sort((a, b) => b.units - a.units);

  const acceleratingSkus = [];
  const skuKeysAll = new Set([...Object.keys(skuRecent), ...Object.keys(skuPrior)]);
  skuKeysAll.forEach((pk) => {
    const r = skuRecent[pk] || 0;
    const p = skuPrior[pk] || 0;
    const meta = skuMap[pk];
    if (!meta) return;
    if (p >= 1 && r > p * 1.2 && r >= 4) {
      acceleratingSkus.push({
        product: meta.product,
        package: meta.package,
        recentUnits: r,
        priorUnits: p,
      });
    } else if (p === 0 && r >= 6) {
      acceleratingSkus.push({
        product: meta.product,
        package: meta.package,
        recentUnits: r,
        priorUnits: 0,
      });
    }
  });
  acceleratingSkus.sort((a, b) => b.recentUnits - a.recentUnits);

  const packageTrendRows = Object.keys({
    ...packageBucketsRecent,
    ...packageBucketsPrior,
  })
    .map((name) => {
      const ru = packageBucketsRecent[name] || 0;
      const pu = packageBucketsPrior[name] || 0;
      const delta =
        pu > 0 ? Math.round(((ru - pu) / pu) * 1000) / 10 : ru > 0 ? null : 0;
      return {
        name,
        recentUnits: ru,
        priorUnits: pu,
        deltaPct: delta,
      };
    })
    .sort((a, b) => b.recentUnits - a.recentUnits);

  const velocityPerDay7d =
    Math.round((unitsLast7d / 7) * 100) / 100;
  const velocityPerDay14d =
    Math.round((unitsLast14d / 14) * 100) / 100;

  const largePackRecent =
    Number(packageBucketsRecent["Tote / bulk"] || 0) +
    Number(packageBucketsRecent["Drum"] || 0) +
    Number(packageBucketsRecent["Pail / cube"] || 0);
  const largePackShareRecent =
    unitsLast14d > 0 ? largePackRecent / unitsLast14d : 0;

  const activeDealersWithDemand = dealerConcentration.length;

  const insights = [];
  const topCat = categoryRows[0];
  if (
    topCat &&
    totalUnits > 0 &&
    topCat.units / totalUnits >= 0.32 &&
    topCat.name !== "Other"
  ) {
    if (topCat.name === "HD Engine Oils") {
      insights.push(
        "HD Engine Oils remain the dominant approved category in this network rollup."
      );
    } else {
      insights.push(
        `${topCat.name} demand remains the strongest category by approved unit volume across active dealers.`
      );
    }
  }

  if (totalUnits > 0 && syntheticUnits / totalUnits >= 0.2) {
    insights.push(
      "Synthetic product approvals represent a significant share of cumulative approved unit volume."
    );
  }

  if (
    syntheticRecent >= 4 &&
    syntheticPrior >= 1 &&
    syntheticRecent > syntheticPrior * 1.2
  ) {
    insights.push(
      "Synthetic approvals are increasing across active territories (recent vs prior 14 days)."
    );
  }

  const catNames = new Set([
    ...Object.keys(catRecent),
    ...Object.keys(catPrior),
  ]);
  catNames.forEach((cat) => {
    const r = catRecent[cat] || 0;
    const p = catPrior[cat] || 0;
    if (r >= 5 && p >= 1 && r > p * 1.25) {
      insights.push(
        `${cat} approvals increased versus the prior 14-day window (approved units only).`
      );
    }
  });

  if (
    hydraulicToteRecent >= 4 &&
    hydraulicToteRecent > Math.max(1, hydraulicTotePrior) * 1.2
  ) {
    insights.push(
      "Hydraulic tote demand is accelerating (approved units in the recent 14-day window)."
    );
  }

  if (toteRecent >= 3 && toteRecent > totePrior) {
    insights.push(
      "Tote or bulk-style package approvals are elevated in the most recent 14 days compared with the prior period."
    );
  }

  if (
    unitsLast14d >= 12 &&
    largePackShareRecent >= 0.38
  ) {
    insights.push(
      "Proposal approvals are concentrating around larger package sizes in the recent 14-day window."
    );
  }

  const topDealer = dealerConcentration[0];
  if (
    topDealer &&
    totalUnits > 0 &&
    topDealer.sharePct >= 40 &&
    dealerConcentration.length >= 2
  ) {
    insights.push(
      `Territory demand is concentrated among dealers—${topDealer.name} accounts for a leading share of approved units in this rollup.`
    );
  }

  const uniqueInsights = Array.from(
    new Map(insights.map((s) => [s.toLowerCase(), s])).values()
  );

  return {
    hasData: lineCount > 0,
    totalApprovedLines: lineCount,
    totalApprovedUnits: totalUnits,
    distinctSkus: distinctSkuCount,
    syntheticUnits,
    syntheticSharePct:
      totalUnits > 0
        ? Math.round((syntheticUnits / totalUnits) * 1000) / 10
        : 0,
    topSkus,
    acceleratingSkus: acceleratingSkus.slice(0, 12),
    categoryRows,
    dealerConcentration,
    packageRows,
    packageTrendRows,
    toteRecent,
    totePrior,
    unitsLast7d,
    unitsLast14d,
    unitsPrior14d,
    velocityPerDay7d,
    velocityPerDay14d,
    largePackShareRecent:
      unitsLast14d > 0
        ? Math.round(largePackShareRecent * 1000) / 10
        : 0,
    activeDealersWithDemand,
    insights: uniqueInsights.slice(0, 12),
  };
}

function buildDealerAdminDashboardInsights(perf) {
  const insights = [];
  if ((perf?.approvedDemandLineCount || 0) === 0) {
    insights.push(
      "Inventory Alerts will populate as customers approve proposals."
    );
  } else if (
    perf?.demandTopCategory &&
    perf.demandTopCategory !== "Other" &&
    (perf.demandCategoryShare || 0) >= 40
  ) {
    insights.push(
      `Approved proposal demand concentrates in ${perf.demandTopCategory} (${perf.demandCategoryShare}% of accepted units).`
    );
  }

  if ((perf?.quotesCreated || 0) > 0 && (perf?.proposalsSent || 0) > 0) {
    insights.push(
      "Quote and proposal submissions are underway across your dealer organization."
    );
  }

  if (
    (perf?.customerResponses || 0) > 0 &&
    (perf?.approvedDemandLineCount || 0) === 0
  ) {
    insights.push(
      "Customers have responded—approved SKUs surface after individual proposal lines are approved."
    );
  }

  if (
    perf?.topQuotedMixName &&
    (perf?.topQuotedMixPercent || 0) >= 38 &&
    (perf?.quotesCreated || 0) > 0
  ) {
    insights.push(
      `Quoted lubricant categories skew toward ${perf.topQuotedMixName} (${perf.topQuotedMixPercent}% of bucketed quote lines).`
    );
  }

  return [...new Set(insights)];
}

function buildManagerDashboardInsights(repSnapshot, demandIntel, assignedRepCount) {
  const insights = [];
  const lines = demandIntel?.approvedLineCount || 0;
  const topCat = demandIntel?.topCategory;
  const catShare = demandIntel?.categoryShare || 0;

  if (lines === 0) {
    insights.push(
      "Inventory Alerts will populate as customers approve proposals."
    );
  } else if (
    topCat &&
    topCat !== "Other" &&
    catShare >= 40
  ) {
    insights.push(
      `Team approved demand concentrates in ${topCat} (${catShare}% of accepted units on scoped quotes).`
    );
  }

  if ((repSnapshot?.quotes || 0) > 0 && (repSnapshot?.proposalsSent || 0) > 0) {
    insights.push(
      "Team activity is building through quote and proposal submissions."
    );
  }

  if ((assignedRepCount || 0) > 0 && (repSnapshot?.quotes || 0) === 0) {
    insights.push(
      "Assigned reps are provisioned—quote volume will populate as reps create opportunities."
    );
  }

  return [...new Set(insights)];
}

function countDeclinedProductAndEquipmentLinesInProposalResponses(responses) {
  let n = 0;
  (responses || []).forEach((res) => {
    getProposalProductResponseArray(res).forEach((item) => {
      if (item.decision === "declined") n += 1;
    });
    const dd = res.decision_data || {};
    const equipmentResponses = Array.isArray(dd.equipment)
      ? dd.equipment
      : Array.isArray(res.equipment)
      ? res.equipment
      : [];
    equipmentResponses.forEach((item) => {
      if (item.decision === "declined") n += 1;
    });
  });
  return n;
}

