/**
 * Label OCR stub. Do not put API keys here — real OCR should call a Supabase Edge Function
 * (or other backend) so secrets stay off the client.
 * @param {File} imageFile
 * @returns {Promise<{ text: string }>}
 */
async function extractLabelTextFromImage(imageFile) {
  if (!imageFile) {
    return { text: "", error: "No image selected" };
  }
  try {
    const base64Image = await new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const result = String(reader.result || "");
        const payload = result.includes(",") ? result.split(",")[1] : result;
        resolve(payload);
      };
      reader.onerror = () => reject(reader.error || new Error("File read failed"));
      reader.readAsDataURL(imageFile);
    });

    const { data, error } = await supabase.functions.invoke("analyze-label-image", {
      body: {
        imageBase64: base64Image,
        filename: imageFile.name || null,
        contentType: imageFile.type || null,
      },
    });
    if (error) {
      console.error("OCR function invoke failed:", error);
      return { text: "", error: error.message || "OCR function failed" };
    }

    const detectedText = String(data?.text || "").trim();
    if (!detectedText) {
      return {
        text: "",
        error: String(data?.error || "No label text detected"),
      };
    }

    return {
      text: detectedText,
      error: "",
      brand: String(data?.brand || "").trim(),
      viscosity: String(data?.viscosity || "").trim(),
      confidence: data?.confidence,
      source: data?.source,
    };
  } catch (err) {
    console.error("OCR extraction failed:", err);
    return { text: "", error: "OCR function failed" };
  }
}

function extractViscosityFromText(text) {
  const m = String(text || "").match(/\b\d{1,2}W-\d{2}\b/i);
  return m ? m[0].toUpperCase() : "";
}

function extractOcrSpecSignals(text) {
  const raw = String(text || "");
  if (!raw.trim()) return [];
  const patterns = [
    /\bAPI\s+[A-Z]{1,2}-?\d(?:\/[A-Z]{1,2}-?\d)?\b/gi,
    /\bCK-4\b/gi,
    /\bCJ-4\b/gi,
    /\bSP\b/gi,
    /\bSN\b/gi,
    /\bCummins\s+CES\s*\d{5}\b/gi,
    /\bCES\s*\d{5}\b/gi,
    /\bVolvo\s+VDS-?\d(?:\.\d)?\b/gi,
    /\bVDS-?\d(?:\.\d)?\b/gi,
    /\bAllison\s+TES[-\s]?\d+\b/gi,
    /\bTES[-\s]?\d+\b/gi,
    /\bDenison\s+HF-\d\b/gi,
    /\bHF-\d\b/gi,
    /\bJDM\s*J\d{2}[A-Z]?\b/gi,
    /\bJ20[CD]\b/gi,
    /\bECF-\d\b/gi,
  ];
  const signals = [];
  patterns.forEach((pattern) => {
    const matches = raw.match(pattern) || [];
    matches.forEach((value) => {
      const normalized = String(value || "").trim();
      if (!normalized) return;
      if (!signals.some((entry) => entry.toLowerCase() === normalized.toLowerCase())) {
        signals.push(normalized);
      }
    });
  });
  return signals.slice(0, 8);
}

function deriveOcrApplicationSignal(text) {
  const value = String(text || "").toLowerCase();
  if (!value) return "";
  if (value.includes("heavy duty diesel")) return "Heavy Duty Diesel";
  if (value.includes("diesel")) return "Diesel Engine";
  if (value.includes("engine oil")) return "Engine Oil";
  if (value.includes("hydraulic")) return "Hydraulic Fluid";
  if (value.includes("transmission") || value.includes("atf")) return "Transmission Fluid";
  if (value.includes("gear")) return "Gear Lubricant";
  if (value.includes("coolant") || value.includes("antifreeze")) return "Coolant / Antifreeze";
  if (value.includes("grease")) return "Grease";
  return "";
}

function normalizeSignalToken(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[®™]/g, "")
    .replace(/[^a-z0-9\-/. ]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function extractMatchedSignalOverlap({
  ocrText,
  ocrSignals,
  detectedViscosity,
  matchedProductName,
  matchedSpecs,
  matchedAliases,
  matchedWhy,
  matchedCategory,
}) {
  const candidateSignals = [];
  if (Array.isArray(ocrSignals)) candidateSignals.push(...ocrSignals);
  const viscosity = String(detectedViscosity || extractViscosityFromText(ocrText) || "").trim();
  if (viscosity) candidateSignals.push(`SAE ${viscosity.toUpperCase()}`);
  const applicationSignals = [
    { label: "Heavy Duty Diesel", pattern: /\bheavy duty diesel\b/i },
    { label: "Diesel Engine", pattern: /\bdiesel\b/i },
    { label: "Engine Oil", pattern: /\bengine oil\b/i },
    { label: "Hydraulic Fluid", pattern: /\bhydraulic\b/i },
    { label: "Transmission Fluid", pattern: /\btransmission\b|\batf\b/i },
    { label: "Gear Lubricant", pattern: /\bgear\b/i },
    { label: "Coolant / Antifreeze", pattern: /\bcoolant\b|\bantifreeze\b/i },
    { label: "Grease", pattern: /\bgrease\b/i },
  ];
  const rawOcrText = String(ocrText || "");
  applicationSignals.forEach((entry) => {
    if (entry.pattern.test(rawOcrText)) {
      candidateSignals.push(entry.label);
    }
  });

  const matchedText = normalizeSignalToken(
    [
      matchedProductName,
      ...(Array.isArray(matchedSpecs) ? matchedSpecs : []),
      ...(Array.isArray(matchedAliases) ? matchedAliases : []),
      matchedWhy,
      matchedCategory,
    ].join(" ")
  );
  if (!matchedText) return [];

  const overlap = [];
  candidateSignals.forEach((signal) => {
    const normalizedSignal = normalizeSignalToken(signal);
    if (!normalizedSignal) return;
    if (matchedText.includes(normalizedSignal)) {
      const display = String(signal || "").trim();
      if (
        display &&
        !overlap.some((item) => normalizeSignalToken(item) === normalizeSignalToken(display))
      ) {
        overlap.push(display);
      }
    }
  });
  return overlap;
}

function shortIdLabel(prefix, value) {
  const raw = String(value || "").trim();
  if (!raw) return `${prefix} —`;
  return `${prefix} ${raw.slice(0, 4)}...`;
}

function normalizeAdvisorText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[®™]/g, "")
    .replace(/[^a-z0-9\-/. ]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function firstAdvisorSentence(text) {
  const value = String(text || "").trim();
  if (!value) return "";
  const parts = value.split(/(?<=[.!?])\s+/);
  return String(parts[0] || value).trim();
}

function extractAdvisorSpecTerms(question) {
  const raw = String(question || "");
  const terms = new Set();
  const patterns = [
    /\b(?:api\s+)?(c[fgjklnops]-\d)\b/gi,
    /\b(ces\s*\d{5})\b/gi,
    /\b(denison\s*hf-\d)\b/gi,
    /\b(hf-\d)\b/gi,
    /\b(acea\s+[a-z]\d(?:\/[a-z]\d)*)\b/gi,
    /\b(vds-\d(?:\.\d)?)\b/gi,
    /\b(eos-\d(?:\.\d)?)\b/gi,
    /\b(gl-\d)\b/gi,
    /\b(mt-\d)\b/gi,
    /\b(jdm\s*j\d{2}[a-z]?)\b/gi,
    /\b(mat\s*\d{4})\b/gi,
  ];
  patterns.forEach((pattern) => {
    let match;
    while ((match = pattern.exec(raw)) !== null) {
      const term = normalizeAdvisorText(match[1]);
      if (term) terms.add(term);
    }
  });
  return Array.from(terms);
}

function advisorFallbackResponse() {
  return {
    intent: "unknown",
    terms: [],
    matches: [],
    answer: "",
    message:
      "The current PDS/spec library does not contain enough information to answer confidently.",
  };
}

const ADVISOR_MANUFACTURER_ALIAS_MAP = {
  caterpillar: ["cat", "caterpillar", "ecf", "to-4", "to-4m"],
  "john deere": ["john deere", "jd", "jdm", "j20c", "j20d"],
  jcb: ["jcb"],
  gm: ["gm", "general motors", "dexos", "dexos1", "dexos2", "dexosd"],
  cummins: [
    "cummins",
    "ces",
    "ces 20086",
    "ces 20087",
    "ces 20074",
    "ces 14603",
  ],
  detroit: [
    "detroit",
    "detroit diesel",
    "dfs",
    "93k",
    "93k222",
    "93k223",
    "93k216",
    "93k217",
  ],
  mack: ["mack", "eos", "eos-4.5", "go-j", "go-h", "to-a plus"],
  volvo: ["volvo", "vds", "vds-4", "vds-4.5"],
  allison: ["allison", "tes", "tes-295", "tes 668", "c-4", "c4"],
  ford: ["ford", "wss", "m2c"],
  hydraulic_oem: ["denison", "hf-0", "hf-1", "hf-2", "eaton", "vickers"],
};

function getAdvisorManufacturerAliases(question) {
  const normalized = normalizeAdvisorText(question);
  const aliasTerms = new Set();
  Object.values(ADVISOR_MANUFACTURER_ALIAS_MAP).forEach((aliases) => {
    const normalizedAliases = (aliases || [])
      .map((alias) => normalizeAdvisorText(alias))
      .filter(Boolean);
    const clusterMatched = normalizedAliases.some((alias) =>
      normalized.includes(alias)
    );
    if (!clusterMatched) return;
    normalizedAliases.forEach((alias) => {
      const token = normalizeAdvisorText(alias);
      if (token) aliasTerms.add(token);
    });
  });
  return Array.from(aliasTerms);
}

function lookupLubricantAdvisor(question) {
  const normalizedQuestion = normalizeAdvisorText(question);
  if (!normalizedQuestion) {
    return {
      intent: "unknown",
      terms: [],
      matches: [],
      answer: "",
      message: "Enter a spec or requirement to search the PDS/spec library.",
    };
  }

  const terms = extractAdvisorSpecTerms(question);
  const isComparisonQuestion =
    /\b(vs|versus|compare|difference|better than|over)\b/i.test(question);
  const isBenefitQuestion =
    /\b(why|advantage|benefit|benefits|application|applications|use|severe service|synthetic blend|full synthetic)\b/i.test(
      question
    );

  const fallbackTerms = normalizedQuestion
    .split(" ")
    .filter((part) => part.length >= 3)
    .slice(0, 8);
  const manufacturerAliases = getAdvisorManufacturerAliases(question);
  const baseTerms = terms.length ? terms : fallbackTerms;
  const searchTerms = Array.from(
    new Set([...baseTerms, ...manufacturerAliases].map((term) => normalizeAdvisorText(term)).filter(Boolean))
  );

  const matches = Object.entries(PDS_MAP)
    .map(([productName, entry]) => {
      const specs = Array.isArray(entry?.specs) ? entry.specs : [];
      const aliases = Array.isArray(entry?.aliases) ? entry.aliases : [];
      const why = String(entry?.why || "").trim();
      const searchText = normalizeAdvisorText(
        [productName, why, ...specs, ...aliases].join(" ")
      );
      const matchedTerms = searchTerms.filter((term) =>
        searchText.includes(normalizeAdvisorText(term))
      );
      const matchedSpec = specs.find((spec) =>
        searchTerms.some((term) =>
          normalizeAdvisorText(spec).includes(normalizeAdvisorText(term))
        )
      );
      return {
        productName,
        why,
        specs,
        url: String(entry?.url || "").trim(),
        matchedTerms,
        matchedSpec: matchedSpec || "",
        relevanceScore: matchedTerms.length,
      };
    })
    .filter((row) => row.matchedTerms.length > 0)
    .sort((a, b) => b.relevanceScore - a.relevanceScore)
    .slice(0, 5);

  if (terms.length > 0) {
    if (!matches.length) {
      return {
        intent: "spec",
        terms,
        matches: [],
        answer: "",
        message:
          "No matching Klondike products were found in the current PDS/spec library.",
      };
    }
    return {
      intent: "spec",
      terms,
      matches,
      answer:
        "These products in the current PDS/spec library match the requested specification.",
      message: "",
    };
  }

  if (manufacturerAliases.length > 0) {
    if (!matches.length) {
      return {
        intent: "manufacturer",
        terms: manufacturerAliases,
        matches: [],
        answer: "",
        message:
          "No matching Klondike products were found in the current PDS/spec library.",
      };
    }
    return {
      intent: "manufacturer",
      terms: manufacturerAliases,
      matches,
      answer:
        "These products in the current PDS/spec library match the requested manufacturer/spec terms.",
      message: "",
    };
  }

  if (isComparisonQuestion) {
    if (matches.length < 2) {
      return advisorFallbackResponse();
    }
    const first = matches[0];
    const second = matches[1];
    return {
      intent: "comparison",
      terms: searchTerms,
      matches: [first, second],
      answer: `${first.productName}: ${firstAdvisorSentence(
        first.why
      )} ${second.productName}: ${firstAdvisorSentence(second.why)}`,
      message: "",
    };
  }

  if (isBenefitQuestion) {
    if (!matches.length) {
      return advisorFallbackResponse();
    }
    const top = matches[0];
    const supportProducts = matches.slice(0, 3).map((row) => row.productName);
    const supportLabel = supportProducts.length
      ? ` Relevant products: ${supportProducts.join(", ")}.`
      : "";
    return {
      intent: "benefit",
      terms: searchTerms,
      matches: matches.slice(0, 3),
      answer: `${firstAdvisorSentence(top.why)}${supportLabel}`,
      message: "",
    };
  }

  return advisorFallbackResponse();
}

