  const loadDealerPerformance = async () => {
  if (!activeMembership?.organization_id) return;

  const { data: quoteRows, error: quoteError } = await supabase
    .from("quotes")
    .select("*")
    .eq("organization_id", activeMembership.organization_id);

  if (quoteError) {
    console.error("Dealer performance quote load error:", quoteError);
    return;
  }

  const dealerQuotes = quoteRows || [];
  const quoteIds = dealerQuotes.map((q) => q.id).filter(Boolean);

  let responseRows = [];
  let itemRows = [];

  if (quoteIds.length > 0) {
    const { data: responses } = await supabase
      .from("proposal_responses")
      .select("*")
      .in("quote_id", quoteIds);

    responseRows = responses || [];

    const { data: items } = await supabase
      .from("quote_items")
      .select("*")
      .in("quote_id", quoteIds);

    itemRows = items || [];
  }

  const approvedResponses = responseRows.flatMap((row) => {
    const productResponses = getProposalProductResponseArray(row);
    const dd = row.decision_data || {};
    const equipmentResponses = Array.isArray(dd.equipment)
      ? dd.equipment
      : Array.isArray(row.equipment)
      ? row.equipment
      : [];
    return [...productResponses, ...equipmentResponses].filter(
      (item) => item.decision === "approved"
    );
  });

  const totalResponses = responseRows.flatMap((row) => {
    const productResponses = getProposalProductResponseArray(row);
    const dd = row.decision_data || {};
    const equipmentResponses = Array.isArray(dd.equipment)
      ? dd.equipment
      : Array.isArray(row.equipment)
      ? row.equipment
      : [];
    return [...productResponses, ...equipmentResponses];
  });

  const revenueWon = approvedResponses.reduce(
    (sum, item) => sum + Number(item.price || 0),
    0
  );

  const repMap = {};

  dealerQuotes.forEach((quote) => {
    const repKey = quote.rep_email || quote.user_id || "Unassigned Rep";

    if (!repMap[repKey]) {
      repMap[repKey] = {
        name: quote.rep_name || quote.rep_email || "Unassigned Rep",
        quotes: 0,
        proposals: 0,
        responses: 0,
        revenue: 0,
      };
    }

    repMap[repKey].quotes += 1;

    if (quote.status === "sent" || quote.review_status) {
      repMap[repKey].proposals += 1;
    }
  });

  responseRows.forEach((row) => {
    const quote = dealerQuotes.find((q) => q.id === row.quote_id);
    const repKey = quote?.rep_email || quote?.user_id || "Unassigned Rep";

    if (repMap[repKey]) {
      repMap[repKey].responses += 1;

      const productResponses = getProposalProductResponseArray(row);
      const dd = row.decision_data || {};
      const equipmentResponses = Array.isArray(dd.equipment)
        ? dd.equipment
        : Array.isArray(row.equipment)
        ? row.equipment
        : [];

      repMap[repKey].revenue += [...productResponses, ...equipmentResponses]
        .filter((item) => item.decision === "approved")
        .reduce((sum, item) => sum + Number(item.price || 0), 0);
    }
  });

  const productBuckets = {
    "Heavy Duty": 0,
    Automotive: 0,
    "Hydraulic Fluids": 0,
    Grease: 0,
    Coolants: 0,
    "Transmission Fluids": 0,
    Equipment: 0,
  };

  itemRows.forEach((item) => {
    const name = `${item.product_name || item.klondike_product || ""}`.toLowerCase();

    if (name.includes("grease")) productBuckets.Grease += 1;
    else if (name.includes("coolant")) productBuckets.Coolants += 1;
    else if (name.includes("hydraulic")) productBuckets["Hydraulic Fluids"] += 1;
    else if (name.includes("transmission") || name.includes("atf")) productBuckets["Transmission Fluids"] += 1;
    else if (name.includes("diesel") || name.includes("engine") || name.includes("15w") || name.includes("10w")) productBuckets["Heavy Duty"] += 1;
    else productBuckets.Automotive += 1;
  });

  const totalProductCount =
    Object.values(productBuckets).reduce((sum, count) => sum + count, 0) || 1;

  const quoteItemLookup = buildQuoteItemLookupById(itemRows);
  const demandSummary = summarizeApprovedDemandFromProposalRows(
    responseRows,
    quoteItemLookup
  );

  const quoteIdsResponded = new Set(
    (responseRows || []).map((r) => r.quote_id).filter(Boolean)
  ).size;

  const quotesAwaitingCustomer = dealerQuotes.filter(
    (q) =>
      q.status === "sent" &&
      String(q.review_status || "").toLowerCase() !== "submitted"
  ).length;

  const topQuotedMixRow = [...Object.entries(productBuckets)]
    .filter(([, cnt]) => cnt > 0)
    .sort((a, b) => b[1] - a[1])[0];

  const topQuotedMixPercent =
    topQuotedMixRow && totalProductCount > 0
      ? Math.round((topQuotedMixRow[1] / totalProductCount) * 100)
      : 0;

  let declinedLineCount = 0;
  responseRows.forEach((row) => {
    getProposalProductResponseArray(row).forEach((item) => {
      if (item.decision === "declined") declinedLineCount += 1;
    });
    const ddr = row.decision_data || {};
    const equipmentResponses = Array.isArray(ddr.equipment)
      ? ddr.equipment
      : Array.isArray(row.equipment)
      ? row.equipment
      : [];
    equipmentResponses.forEach((item) => {
      if (item.decision === "declined") declinedLineCount += 1;
    });
  });

  let ocrTimelineRows = [];
  try {
    const { data: ocrData, error: ocrTimelineError } = await supabase
      .from("ocr_scan_events")
      .select(
        "id, created_at, detected_brand, detected_viscosity, match_success, matched_klondike_product, image_source_type, rep_id"
      )
      .eq("dealer_id", activeMembership.organization_id)
      .order("created_at", { ascending: false })
      .limit(30);
    if (ocrTimelineError) {
      console.error("Dealer timeline OCR load error:", ocrTimelineError);
    } else {
      ocrTimelineRows = ocrData || [];
    }
  } catch (err) {
    console.error("Dealer timeline OCR load error:", err);
  }

  let dealerViewEvents = [];
  try {
    if (quoteIds && quoteIds.length > 0) {
      const { data: viewRows, error: viewError } = await supabase
        .from("proposal_view_events")
        .select("quote_id, viewed_at")
        .in("quote_id", quoteIds);
      if (!viewError) dealerViewEvents = viewRows || [];
      else console.warn("Proposal view events load failed:", viewError);
    }
  } catch (ve) {
    console.warn("Proposal view events load failed:", ve);
  }

  setDealerTimelineBundle({
    quotes: dealerQuotes,
    responses: responseRows,
    ocrEvents: ocrTimelineRows,
    viewEvents: dealerViewEvents,
  });

  // Proposal delivery/view intelligence (proposal link opens).
  try {
    const dealerDeliveryIntel = buildProposalDeliveryIntelligence({
      quotes: dealerQuotes,
      proposalResponses: responseRows,
      viewEvents: dealerViewEvents,
      mode: "dealer",
    });
    setDealerAdminProposalDeliveryIntel(dealerDeliveryIntel);
  } catch (e) {
    console.warn("Proposal delivery intelligence compute skipped:", e);
    setDealerAdminProposalDeliveryIntel(null);
  }

  setDealerPerformance({
    quotesCreated: dealerQuotes.length,
    proposalsSent: dealerQuotes.filter((q) => q.status === "sent").length,
    customerResponses: responseRows.length,
    revenueWon,
    approvalRate:
      totalResponses.length > 0
        ? Math.round((approvedResponses.length / totalResponses.length) * 100)
        : 0,
    leaderboard: Object.values(repMap).sort((a, b) => b.revenue - a.revenue),
    productMix: Object.entries(productBuckets).map(([name, count]) => ({
      name,
      percent: Math.round((count / totalProductCount) * 100),
      count,
    })),
    followUps: dealerQuotes
      .filter((q) => q.status === "sent" || q.review_status === "open")
      .slice(0, 5),
    demandDistinctSkus: demandSummary.distinctSkus,
    demandTotalUnits: demandSummary.totalUnits,
    demandTopCategory: demandSummary.topCategory,
    demandCategoryShare: demandSummary.categoryShare,
    approvedDemandLineCount: demandSummary.approvedLineCount,
    quotesWithCustomerResponse: quoteIdsResponded,
    quotesAwaitingCustomer,
    topQuotedMixName: topQuotedMixRow ? topQuotedMixRow[0] : null,
    topQuotedMixPercent,
    declinedLineCount,
  });
};
